def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        score = 0.0
        factor = 1.0
        penalty = 0.0
        boost = 0.0
        for j in range(1, 15):
            if j % 3 == 0:
                factor *= 1.02
            elif j % 5 == 0:
                factor *= 0.95
            if ratio < 0.1 * j:
                score += (j ** 2) * np.exp(-ratio*j) * factor
            else:
                score += np.log1p(j*j) * factor / (j + 2)
            if cap % (j + 2) == 0:
                penalty += np.sqrt(j) / (j + 3)
            else:
                penalty -= np.log1p(j) / (j + 1)
            if (cap + j) % 4 == 0:
                boost += np.sin(ratio * j) * factor
            else:
                boost -= np.cos(ratio * j) * factor
            if j == 10:
                for k in range(1, 7):
                    diff = cap - item * k * (j % 3 + 1)
                    if diff > 0:
                        if diff % 3 == 0:
                            score += (diff ** 0.3) / (k + 1)
                        else:
                            score -= np.log1p(abs(diff)) / (k + 2)
                    else:
                        penalty += (abs(diff) ** 1.2) / (k + 3)
        score += penalty * 0.5 + boost * 0.3
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            priorities[i] = -score * np.log1p(cap + item) * (1 + ratio)
        else:
            if cap > item * 7:
                priorities[i] = -score / (np.sqrt(cap) + 2) * (1 - ratio / 2)
            else:
                priorities[i] = -score / (cap + 3) * (1 + ratio / 3)
        if ratio > 1.2:
            priorities[i] *= 1.5
        elif ratio < 0.05:
            priorities[i] *= 0.7
        extra_penalty = 0.0
        for m in range(1, 4):
            if cap % (m + 1) == 0 and item % (m + 2) != 0:
                extra_penalty += np.exp(-m * ratio)
            elif (cap + m) % 5 == 0:
                extra_penalty -= np.log1p(m * item)
        priorities[i] += extra_penalty * 0.4
        if priorities[i] > 1000 or np.isnan(priorities[i]) or np.isinf(priorities[i]):
            priorities[i] = np.inf
    return priorities
